source:
OPT-NC
{{ .Site.BaseURL }}
{{ now.Format "Mon, 02 Jan 2006 15:04:05 -0700" }}

{{/* 🎯 On pilote le flux par les PAGES réelles (et non par les data files) :
     cela garantit que l'URL diffusée existe vraiment et pointe sur la fiche publiée.
     Les champs riches (missions, compétences) sont récupérés dans le JSON associé.
     Les champs simples sont en texte XML échappé ; seule la description (HTML) est en CDATA. */}}
{{ range .Site.RegularPages }}
  {{ if .Params.ref }}
    {{ $page := . }}
    {{ $key := replace .Params.ref "/" "_" }}
    {{ with index $.Site.Data.avps $key }}

    {{ .title | htmlUnescape }}
    {{ .identifier }}

    {{/* ✅ URL canonique réelle de la fiche (et non un chemin /avps/ inexistant) */}}
    {{ $page.Permalink }}

    OPT-NC
    {{ .datePosted }}

    {{ with .validThrough }}{{ . }}{{ end }}

    {{ $city := "Nouméa" }}
    {{ if .applicantLocationRequirements }}
      {{ with .applicantLocationRequirements.address }}{{ $city = .addressLocality }}{{ end }}
    {{ else if .jobLocation }}
      {{ with .jobLocation.address }}{{ $city = .addressLocality }}{{ end }}
    {{ end }}
    {{ $city }}
    Nouvelle-Calédonie

    {{ .occupationalCategory | default "Autres métiers" | htmlUnescape }}

    {{ "" | safeHTML }}
      {{ with .description }}
        <p><strong>Description du poste :</strong><br>{{ . | htmlUnescape | safeHTML }}</p>
      {{ end }}

      {{ with .responsibilities }}
        <p><strong>Missions principales :</strong></p>
        <ul>
          {{ range . }}<li>{{ . | htmlUnescape | safeHTML }}</li>{{ end }}
        </ul>
      {{ end }}

      {{ with .skills }}
        <p><strong>Compétences et profil recherché :</strong></p>
        <ul>
          {{ range . }}<li>{{ . | htmlUnescape | safeHTML }}</li>{{ end }}
        </ul>
      {{ end }}
    {{ "" | safeHTML }}

    {{ end }}
  {{ end }}
{{ end }}
